import React, { useState } from 'react';
import { Link } from 'react-router-dom';

const Katalog = () => {
  // Contoh data sementara sebelum nanti ditarik dari MySQL via Node.js
  const [produk] = useState([
    { id: 1, nama: 'Black Forest', harga: 'Rp 150.000', img: 'blackforest.jpg' },
    { id: 2, nama: 'Bolu Cukke', harga: 'Rp 60.000', img: 'bolucukke.jpg' }
  ]);

  return (
    <div style={{ padding: '20px' }}>
      <h1>Katalog Produk Kue</h1>
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: '20px' }}>
        {produk.map((kue) => (
          <div key={kue.id} style={{ border: '1px solid #ddd', padding: '10px', borderRadius: '8px' }}>
            <h3>{kue.nama}</h3>
            <p>{kue.harga}</p>
            <Link to={`/produk/${kue.id}`}>Lihat Detail</Link>
          </div>
        ))}
      </div>
    </div>
  );
};

export default Katalog;
